          right={
            <div className="flex h-full flex-col">
              <div className="flex-1 overflow-y-auto">
                <DecisionPanel
                  conflictId={activeId}
                  selectedClaimIndex={selectedClaimIndex}
                />
              </div>
              <TrustWeightsPanel />
            </div>
          }
        />
      </div>
    </div>
  )
}

function ViewToggle({ view, onChange }: { view: View; onChange: (v: View) => void }) {
