      </button>
      <button
        onClick={() => onChange('pending_types')}
        className={`rounded px-3 py-1 text-sm font-medium transition-colors ${
          view === 'pending_types'
            ? 'bg-foreground text-background'
            : 'text-muted-foreground hover:text-foreground'
        }`}
      >
        Pending types
      </button>
    </div>
  )
}

